MOD = 998244353

def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    N = int(data[0])
    M = int(data[1])
    S = data[2]

    # Initialize DP table: dp[i][j][l] represents the number of strings of length j
    # using the first i characters of S with LCS length l
    dp = [[[0] * (N + 1) for _ in range(M + 1)] for __ in range(N + 1)]
    dp[0][0][0] = 1

    for i in range(N + 1):
        for j in range(M + 1):
            for l in range(N + 1):
                if dp[i][j][l] == 0:
                    continue
                # Consider adding a new character to the generated string
                for c in range(26):
                    char = chr(ord('a') + c)
                    # Character not present in S, does not affect LCS
                    if char not in S:
                        dp[i][j + 1][l] = (dp[i][j + 1][l] + dp[i][j][l]) % MOD
                    else:
                        # Find the position of this character in S
                        pos = S.find(char)
                        # If the character is not in the current prefix of S, it's same as above
                        if pos >= i:
                            # The character can be added to the LCS, increasing the length by 1
                            if l + 1 <= N:
                                dp[i + 1][j + 1][l + 1] = (dp[i + 1][j + 1][l + 1] + dp[i][j][l]) % MOD
                        else:
                            # The character is already considered, does not increase LCS length
                            dp[i][j + 1][l] = (dp[i][j + 1][l] + dp[i][j][l]) % MOD

    # Compute answers for each k from 0 to N
    ans = [0] * (N + 1)
    for k in range(N + 1):
        ans[k] = dp[N][M][k]

    print(' '.join(map(str, ans)))

if __name__ == "__main__":
    main()
